parameters.jsCode:
const remoteJid = $('Webhook').item.json.body.data.key.remoteJid;
const remoteJidAlt = $('Webhook').item.json.body.data.key.remoteJidAlt;

// Verifica qual contém .whatsapp.net e retorna o valor completo
let telefone;

if (remoteJid && remoteJid.includes('.whatsapp.net')) {
  telefone = remoteJid;
} else if (remoteJidAlt && remoteJidAlt.includes('.whatsapp.net')) {
  telefone = remoteJidAlt;
} else {
  // Fallback: se nenhum tiver .whatsapp.net, usa remoteJid como padrão
  telefone = remoteJid || remoteJidAlt || null;
}

return {
  telefone: telefone
};
